    <user id="1">
        <name>alice</name>
        <role>admin</role>
        <credentials>
            <password>alice_password_hash</password>
        </credentials>
    </user>
    <user id="2">
        <name>bob</name>
        <role>user</role>
        <credentials>
            <password>bob_password_hash</password>
        </credentials>
    </user>
    <user id="3">
        <name>charlie</name>
        <role>guest</role>
        <credentials>
            <password>charlie_password_hash</password>
        </credentials>
    </user>
</users>```


## Output Format

